import math

def vae_loss(x, x_recon, mu, sigma_sq):
    recon = (x - x_recon)**2
    if mu == 0 and sigma_sq == 1:
        kl = 0
    else:
        kl = 0.5 * (mu**2 + sigma_sq - math.log(sigma_sq) - 1)
    return recon + kl

# Example: x=5, x̂=4, μ=0, σ²=1
print(vae_loss(5, 4, 0, 1))  # 1.0
